String _clean(dynamic v) {
  if (v == null) return '';
  final s = v.toString().trim();
  return (s.isEmpty || s == 'null') ? '' : s;
}

String _preprocessGenres(String raw) {
  final pattern = RegExp(r'"genres":"\[(.*?)\]"');
  return raw.replaceAllMapped(pattern, (m) {
    final inner = m.group(1)!;
    return '"genres":[' + inner + ']';
  });
}

List<dynamic> _decodeByObjectSlices(String raw) {
  final out = <dynamic>[];
  final fixed = _preprocessGenres(raw);
  const marker = '{"idx":';
  int pos = 0;
  final starts = <int>[];
  while (true) {
    final i = fixed.indexOf(marker, pos);
    if (i == -1) break;
    starts.add(i);
    pos = i + marker.length;
  }
  if (starts.isEmpty) return out;

  for (int s = 0; s < starts.length; s++) {
    final start = starts[s];
    final endLimit = s + 1 < starts.length ? starts[s + 1] : fixed.length;
    String slice = fixed.substring(start, endLimit);
    final lastClose = slice.lastIndexOf('}');
    if (lastClose != -1) slice = slice.substring(0, lastClose + 1);
    try {
      out.add(jsonDecode(slice));
    } catch (_) {
      final t = slice.trimRight();
      if (!t.endsWith('}')) {
        try {
          out.add(jsonDecode('$t}'));
        } catch (_) {}
      }
    }
  }
  return out;
}

List<dynamic> _safeDecodeTrending(String raw) {
  try {
    return jsonDecode(raw);
  } catch (_) {
    final fixed = _preprocessGenres(raw);
    try {
      return jsonDecode(fixed);
    } catch (_) {
      return _decodeByObjectSlices(fixed);
    }
  }
}

String _langCode(dynamic v) {
  final s = _clean(v).toLowerCase();
  if (s.isEmpty) return '';
  final primary = s.split(RegExp(r'[-_]')).first;
  return primary;
}

List<String> _genresList(dynamic v) {
  if (v == null) return const <String>[];
  if (v is List) {
    return v.map((e) => _clean(e)).where((e) => e.isNotEmpty).toList();
  }
  final s = _clean(v);
  if (s.isEmpty) return const <String>[];
  if (s.startsWith('[') && s.endsWith(']')) {
    try {
      final decoded = jsonDecode(s);
      if (decoded is List) {
        return decoded
            .map((e) => _clean(e))
            .where((e) => e.isNotEmpty)
            .toList();
      }
    } catch (_) {}
    final inner = s.substring(1, s.length - 1);
    return inner
        .split(',')
        .map((e) => e.replaceAll('"', '').trim())
        .where((e) => e.isNotEmpty)
        .toList();
  }
  return s
      .split(RegExp(r'[,\|/]'))
      .map((e) => e.trim())
      .where((e) => e.isNotEmpty)
      .toList();
}

List<Map<String, dynamic>> parseTrendingMovies() {
  final List<dynamic> raw = _safeDecodeTrending(trendingMoviesJson);
  return raw.map((m) {
    final releaseDate = _clean(m['releaseDate']);
    final year = releaseDate.length >= 4 ? releaseDate.substring(0, 4) : '';
    final backdrop = _clean(m['backdropPath']);
    final poster = _clean(m['posterPath']);
    final image =
        (backdrop.isNotEmpty
            ? backdrop
            : 'https://via.placeholder.com/300x450?text=No+Image');

    final originalLang = _clean(m['originalLang']);
    final langCode = _langCode(originalLang);
    final genresVal = m['genres'];
    final genres = _genresList(genresVal);
    final popVal = m['popularity'];
    final popularity =
        (popVal is num)
            ? popVal.toDouble()
            : double.tryParse(_clean(popVal)) ?? 0.0;

    final va = m['voteAverage'];
    final voteAverageNum =
        (va is num) ? va.toDouble() : double.tryParse(_clean(va)) ?? 0.0;

    return <String, dynamic>{
      'title': _clean(m['title']),
      'image': image,
      'poster': poster,
      'backdrop': backdrop,
      'year': year,
      'lang': originalLang.toUpperCase(),
      'langCode': langCode,
      'rating':
          _clean(m['voteAverage']).isEmpty ? '0' : _clean(m['voteAverage']),
      'description': _clean(m['overview']),
      'genres': genres,
      'popularity': popularity,
      'voteAverageNum': voteAverageNum,
    };
  }).toList();
}
